    it('always: unnamed always', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ mapping: fc.string() }) }),
              fc.record({ action: fc.constant('create'), input: fc.record({ name: fc.string({ minLength: 1, maxLength: 50 }), widget_id: fc.string({ minLength: 1, maxLength: 50 }), schema: fc.string({ minLength: 1, maxLength: 50 }), display_mode: fc.string({ minLength: 1, maxLength: 50 }), insertable: fc.string(), block_editor_context: fc.string() }) }),
              fc.record({ action: fc.constant('bindSlot'), input: fc.record({ mapping: fc.string(), slot_name: fc.string({ minLength: 1, maxLength: 50 }), sources: fc.string() }) }),
              fc.record({ action: fc.constant('bindProp'), input: fc.record({ mapping: fc.string(), prop_name: fc.string({ minLength: 1, maxLength: 50 }), source: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('bindAction'), input: fc.record({ mapping: fc.string(), actionPart: fc.string({ minLength: 1, maxLength: 50 }), binding: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('render'), input: fc.record({ mapping: fc.string(), context: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('preview'), input: fc.record({ mapping: fc.string(), entity_id: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('lookup'), input: fc.record({ schema: fc.string({ minLength: 1, maxLength: 50 }), display_mode: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ mapping: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = componentMappingHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(componentMappingHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

